import { GameFIG_VV } from "../GameFIG/GameFIG_VV";
import { GameFIG_Config } from "../GameFIG/GameFIG_Config";



var windowUse_this;
//使用本脚本请使用WindowUse.Get() 方法，切勿单独new 
//本脚本控制所有场景需要预先加载的资源,本游戏资源不多在Loading.js全部预加载完毕~ 请合理使用，例如多个场景资源过多，切换时注意优先清理关闭场景资源，再缓存新场景资源。
//本脚本仅作为跨脚本共用脚本，并非主逻辑脚本！主逻辑请挂置主场景对应Runtime！列如：家里和学校都可以使用的新手引导
//本脚本所有数据仅临时储存，与GameGIF逻辑不同，此脚本为场景逻辑数据交互，GameGIF更多是玩家数据和其他对外接口和一些常用函数！
//综上所述 此脚本不能“公用”仅提供逻辑参考，不要与GameGIF 同时拷贝到其他项目使用！！！！！！！！
/**公共变量函数储存脚本 */
export default class windowUse extends Laya.Script {

    constructor() {
        super();
        this.GameFIG_Config = GameFIG_Config;
        this.GameFIG = GameFIG_VV.Get();
        this.MapLeng = 7;
        this.HuaBiFIG = [
            { ID: 0, name: "铅笔", color: "#ff0000", H: 10, URL: "Pen/0.png" },
            { ID: 1, name: "羽毛", color: "#d23f1", H: 5, URL: "Pen/1.png" },
            { ID: 2, name: "口红", color: "#ec162f", H: 18, URL: "Pen/3.png" },
            { ID: 3, name: "魔法棒", color: "#29ff20", H: 7, URL: "Pen/2.png" },
            { ID: 4, name: "玫瑰", color: "#ee7c58", H: 8, URL: "Pen/4.png" },
        ]
    }

    /**
     * Get 单例获取全局变量储存脚本
     * @return {windowUse} 
     */
    static Get() {
        if (windowUse_this == undefined) {
            windowUse_this = new windowUse();
        }
        return windowUse_this;
    }
    /**
         * 根据页面加载地图
         * @param {Number} NowYE 当前页
         * @param {Laya.Handler} OverHander 回调 (PIC返回场景图片集合 ID返回当前第几个 YEID返回当前第几页)
         */
    LoadMapPic(NowYE, OverHander = Laya.Handler.create()) {
        this.NowYE = NowYE;
        this.nowID = this.GameFIG_Config.player_Config.NowGK % 6;//第几个
        var nowIDArr = [];
        for (var a = NowYE * 6, b = 0; b < 6 && a < this.MapLeng; a++, b++) {
            nowIDArr.push(a);
        }

        var Loadmuch = 0;
        if (this.sceneArrPIC) {//销毁一下图片 防止GPU暴增 //关卡少可以循环使用不销毁 关卡过多GPU负载过高 及时清理
            for (var a = 0; a < this.sceneArrPIC.length; a++) {
                this.sceneArrPIC[a].destroy();
            }
        }

        this.sceneArrPIC = [];
        for (var a = 0; a < nowIDArr.length; a++) {
            Laya.Scene.load("Map/" + nowIDArr[a] + ".scene", Laya.Handler.create(this, (scene) => {
                var texture = scene.drawToTexture(scene.width, scene.height, 0, 0);
                this.sceneArrPIC.push(texture);
                Loadmuch++;
                if (Loadmuch == nowIDArr.length) {
                    OverHander.runWith([this.sceneArrPIC, this.nowID, NowYE])
                }
            }))
        }
    }
}