
/**
 * 本示例采用非脚本的方式实现，而使用继承页面基类，实现页面逻辑。在IDE里面设置场景的Runtime属性即可和场景进行关联
 * 相比脚本方式，继承式页面类，可以直接使用页面定义的属性（通过IDE内var属性定义），比如this.tipLbll，this.scoreLbl，具有代码提示效果
 * 建议：如果是页面级的逻辑，需要频繁访问页面内多个元素，使用继承式写法，如果是独立小模块，功能单一，建议用脚本方式实现，比如子弹脚本。
 */


import { GameFIG_Config } from "../GameFIG/GameFIG_Config.js";
import { GameFIG_VV } from "../GameFIG/GameFIG_VV.js";

import windowUse from "./windowUse.js";



window.FilterOne = { showXu: null };//仅一个背景虚化遮罩否则严重闪屏
//主场景父类
export default class GameAll extends Laya.Scene {
    constructor() {
        super();
        this.viewAll = {
            GameUI: "View/GameUI.scene",//主界面
            Win: "View/GameWin.scene"
        }
        this.GameFIG = GameFIG_VV.Get();
        this.GameFIG_Config = GameFIG_Config;
        this.windowUser = windowUse.Get();

    }
    SetBackAotu() {
        this.ScaleCenter = (Laya.stage.height / this.back.height)
        if (Laya.stage.height > 1334) {

            this.back.width = this.ScaleCenter * this.back.width;
            this.back.x = Laya.stage.width / 2 - this.back.width / 2;
        }
        this.back.height = Laya.stage.height;
    }
    PoolDelog() {
        var Delog = new Laya.Image();
        Delog.skin = "Login/log/b.png";
        var Lable = new Laya.Label();
        Lable.bold = true;
        Lable.color = "#91e58e";
        Lable.fontSize = 25;
        Lable.align = "center";
        Lable.valign = "middle";
        Lable.width = 480;
        Lable.height = 188;
        Lable.wordWrap = true;
        Delog.addChild(Lable);
        Delog.biaoti = Lable;
        Delog.width = 480;
        Delog.height = 190;
        Delog.pivot(240, 95);
        return Delog;

    }

    /**
     * 游戏内置弹窗
     * @param {*} msg 文本 
     * @param {*} time 展示时间 
     * @param {*} TFMask 是否遮挡 会防止用户点击屏幕
     * @param {Laya.Handler} overHander 结束回调
     * @returns {Laya.Image} time为0则不会自动消失 会返回一个对象给你调用 .hide(time:消失等待时间) 会自动消失并回收
     */
    DeLog(msg = "", time = 1500, TFMask = false, overHander) {
        var DelogSprite = Laya.Pool.getItemByCreateFun("Delog", this.PoolDelog, this);
        DelogSprite.biaoti.text = msg;
        DelogSprite.alpha = 1;
        DelogSprite.scaleX = 1;
        DelogSprite.scaleY = 1;
        Laya.stage.addChild(DelogSprite);
        DelogSprite.pos(Laya.stage.width / 2, Laya.stage.height / 2, true);
        DelogSprite.zOrder = 99;
        if (TFMask) {
            Laya.MouseManager.enabled = false;
        }
        Laya.Tween.from(DelogSprite, { scaleX: 0.2, scaleY: 0.2 }, 500, Laya.Ease.backOut, null, 0);

        if (time != 0) {
            var hidehander = Laya.Handler.create(this, (Delogs, TFMasks, overHanders) => {
                if (TFMasks) {
                    Laya.MouseManager.enabled = true;
                }
                if (overHanders) {
                    overHanders.run();
                }
                Laya.Pool.recover("Delog", Delogs);
                Delogs.removeSelf();
            }, [DelogSprite, TFMask, overHander]);
            Laya.Tween.to(DelogSprite, { y: DelogSprite.y - 150 }, 300, Laya.Ease.linearIn, null, time);
            Laya.Tween.to(DelogSprite, { alpha: 0 }, 300, Laya.Ease.linearIn, hidehander, time + 300);
        } else {
            DelogSprite.time = time;
            DelogSprite.TFMask = TFMask;
            DelogSprite.overHander = overHander;
            DelogSprite.hide = function (Hidetime = 0) {
                Laya.Tween.to(this, { alpha: 0 }, 300, Laya.Ease.linearIn, Laya.Handler.create(this, (Delogs, TFMasks, overHanders) => {
                    if (TFMasks) {
                        Laya.MouseManager.enabled = true;
                    }
                    if (this.overHanders) {
                        this.overHanders.run();
                    }
                    Laya.Pool.recover("Delog", Delogs);
                    Delogs.removeSelf();
                }, [this, this.TFMask, this.overHander]), Hidetime);
            }.bind(DelogSprite);
            return DelogSprite;
        }


    }
    /**
     * 继用 onClosed 
     */
    Closed() {

    }
    onClosed() {
        this.destroy();
        this.Closed();
    }
    /**
     * 打开其他场景 
     * @param {String} key 地址
     * @param {*} other 传递参数 {}  EndHaner 结束回调  OpenSetHaner 打开设置完成回调
     * @param {Boolean} TFopenFilter 是否打开背景虚化 
     * @param {Boolean} TFhide 是否隐藏当前界面
     * @param {Boolean} TFclose 是否关闭其他场景 默认false
     * @param {Laya.Handler} LoadOverhander 加载完成回调
     * @param {Laya.Handler} Loadhander 加载进度回调
     * @param {Boolean} ShowTishi 是否显示提示正在加载其他场景 配合other.OpenSetHaner使用 必须同时为true
     */
    OpenView(key = "", other = {}, TFopenFilter = true, TFhide = false, TFclose = false, LoadOverhander, Loadhander, ShowTishi = false) {
        if (other.OpenSetHaner && ShowTishi) {//当前界面还没关闭
            this.windowUser.GameDiaoxianFun_Show("正在加载其他场景");
            Laya.stage.on(Laya.Event.CLICK, this, this.Clickoff);
        }
        //开启整体背景虚化
        if (TFopenFilter) {
            // this.getChildAt(0).srollRect = new Laya.Rectangle( this.getChildAt(0).x * -1, 0, Laya.stage.width, Laya.stage.height)
            this.OpenFilter();
        }
        if (TFhide) {
            this.visible = false;
        }

        //--打开场景 但不关闭当前场景
        Laya.Scene.open(key, TFclose, other, LoadOverhander, Loadhander);

    }
    Show() {
        this.visible = true;
    }
    /**打开背景遮罩 */
    OpenFilter(fiter = this) {
        var blurFilter = new Laya.BlurFilter();
        blurFilter.strength = 10;
        fiter.filters = [blurFilter];
        this.CloseFiter = fiter;
        //  this.visible = false;
        /**********************开启后全局一个虚化，防止多个虚化屏幕出现严重抖动
        // if (window.FilterOne.showXu != null) {
        //     this.LastXuHua = window.FilterOne.showXu;
        //     window.FilterOne.showXu.filters = null;
        // }
        // //注意 打开新虚化背景后会记录关闭之前的虚化背景是那个，当关闭新打开的虚化背景时 就会打开对应关闭的虚化。切勿乱跳
        // window.FilterOne[this["$_GID"].toString()] = this;
        // window.FilterOne.showXu = this;
         */
    }

    HideFilter() {

        if (this.CloseFiter != this) {
            this.visible = true;
            this.CloseFiter.destroy();
        } else {
            this.filters = null;
        }
        /**********************开启后全局一个虚化 
        // delete window.FilterOne[this["$_GID"].toString()];
        // if (this.LastXuHua != undefined) {
        //     var blurFilter = new Laya.BlurFilter();
        //     blurFilter.strength = 10;
        //     this.LastXuHua.filters = [blurFilter];
        //     this.LastXuHua = undefined;
        //     window.FilterOne.showXu = this.LastXuHua;
        // } else {
        //     window.FilterOne.showXu = null;
        // }
        */
    }
    Clickoff() {
        console.log("阻止加载点击")
    }
    /**显示此场景并执行上个场景的回调----防止直接打开页面未及时更新 仅限在不关闭当前场景的情况下 */
    OpenOver() {
        if (this.OpenDmsg.OpenSetHaner) {
            this.windowUser.GameDiaoxianFun_hide();
            Laya.stage.off(Laya.Event.CLICK, this, this.Clickoff);
            this.visible = true;
            this.OpenDmsg.OpenSetHaner.run();
            this.OpenDmsg.OpenSetHaner = undefined;
        }

    }
}