/**游戏运行脚本 画线逻辑 */
export default class GameRun extends Laya.Script {
    /**
     * 
     * @param {Laya.Scene} scene 场景
     * @param {Laya.Scene} GameUI GameUI对象 方便调用主界面UI等
     */
    constructor(scene = new Laya.Scene(), GameUI) {
        super();
        this.windowUser = windowUse.Get();
        this.GameFIG = GameFIG_VV.Get();
        this.GameUI = GameUI;
        this.add = 0
        this.scene = scene;
        this.scene.ShowTishi = this.ShowTishi.bind(this);//抛出方法给GameUI使用
        this.scene.ChangeHuaB = this.ChangeHuaB.bind(this);//抛出方法给GameUI使用
        this.moveCeng = GameUI.SceneBox;
        this.DIG_RADIUS = 3;//半径
        this.DIG_FRAGMENT = 12;//多少条边组成的圆形
        this.ChangeHuaB();
        Laya.stage.hitTestPrior = true;
        this.moveCeng.on(Laya.Event.MOUSE_DOWN, this, this.GameDown);//添加按下监听
        this.SetSceneWall();//设置墙
        this.SetBall();//设置球
        this.SetTishi();//设置提示
        this.MoveJL = 25;//最小间距 绘制检测间距 


    }
    /**切换画笔属性 */
    ChangeHuaB() {
        this.DIG_RADIUS = this.windowUser.HuaBiFIG[this.GameFIG.player_Config.Pen.nowPF].H / 2;//半径
        this.DrawColor = this.windowUser.HuaBiFIG[this.GameFIG.player_Config.Pen.nowPF].color;//颜色
    }
    /**显示提示线 */
    ShowTishi() {
        this.Tishi.visible = true;
    }
    /**设置提示线 */
    SetTishi() {
        this.Tishi = this.scene.getChildByName("Tishi");
        if (this.GameUI.GameRunID <= 2) {//前3关默认显示
            this.Tishi.visible = true;
        }
    }
    /**设置球 */
    SetBall() {
        var BallA = this.scene.getChildByName("BallA");
        var _BallPhy = new BallPhy(this);
        BallA.addComponentIntance(_BallPhy);//添加碰撞触发脚本
        // BallB.addComponent(BallPhy);
    }
    /**设置墙 */
    SetSceneWall() {
        for (var a = 0; a < this.scene.numChildren; a++) {
            var node = this.scene.getChildAt(a);
            if (node.name === "Wall" || node.name === "BallA" || node.name === "BallB") {//给墙添加监听 不能再墙上画
                node.on(Laya.Event.MOUSE_DOWN, this, this.StopPro);
                node.on(Laya.Event.MOUSE_UP, this, this.StopPro);
                node.on(Laya.Event.MOUSE_OUT, this, this.StopPro);
                node.on(Laya.Event.MOUSE_MOVE, this, this.StopPro);
            }
        }
    }
    StopPro(e) {//停止冒泡
        e.stopPropagation();
        if (this.MouseDown) {//防止单独触发按下 不触发抬起
            this.GameUP();
        }

    }
    GameDown() {//按下
        this.GameUI.HuaBiY.visible = true;//显示画笔
        this.SetPenPos();//设置画笔位置
        if (this.moveCeng.mouseX <= Laya.stage.width - (108 + this.DIG_RADIUS / 2)) {//控制画笔 绘制区域
            this.MouseDown = true;
            this.reset();
            Laya.timer.frameLoop(1, this, this.lateUpdate);
            this.MovePos = { x: this.scene.mouseX, y: this.scene.mouseY };//记录按下位置
            this.moveCeng.on(Laya.Event.MOUSE_OUT, this, this.GameUP);
            this.moveCeng.on(Laya.Event.MOUSE_UP, this, this.GameUP);
            this.moveCeng.on(Laya.Event.MOUSE_MOVE, this, this.GameMove);
            if (this.Tishi.visible == true) {//隐藏提示线
                this.Tishi.visible = false;
            }
        }

    }
    GameUP() {//抬起
        this.GameUI.HuaBiY.visible = false;//隐藏画笔
        this.MouseDown = false;
        Laya.timer.clear(this, this.lateUpdate);
        Laya.physicsTimer.resume();
        this.moveCeng.off(Laya.Event.MOUSE_OUT, this, this.GameUP);
        this.moveCeng.off(Laya.Event.MOUSE_UP, this, this.GameUP);
        this.moveCeng.off(Laya.Event.MOUSE_MOVE, this, this.GameMove);
        this.DrawPhy();//添加物理
    }
    GameOut() {
        this.GameUI.HuaBiY.visible = false;
        this.MouseDown = false;
        Laya.timer.clear(this, this.lateUpdate);
        this.moveCeng.off(Laya.Event.MOUSE_OUT, this, this.GameUP);
        this.moveCeng.off(Laya.Event.MOUSE_UP, this, this.GameUP);
        this.moveCeng.off(Laya.Event.MOUSE_MOVE, this, this.GameMove);
    }


    GameMove() {//移动
        if (this.moveCeng.mouseX <= Laya.stage.width - (108 + this.DIG_RADIUS / 2)) {
            var regions = [];
            var pos = { x: this.scene.mouseX, y: this.scene.mouseY };
            var count = this.DIG_FRAGMENT;//圆形
            var xiangcha = Cocos_Api_MG.subtract(pos, this.LastMousePos);
            var ju = Math.sqrt(Cocos_Api_MG.lengthSqr(xiangcha));

            if (ju > this.MoveJL) {//判断距离是否超出绘制距离 太近绘制影响性能 
                // 添加围绕中心点 根据半径和点数绘制的 类圆多边形  计算顶点位置 
                var startPos = Cocos_Api_MG.subtract(pos, xiangcha);
                for (let index = 0; index < count; index++) {
                    var r = 2 * Math.PI * index / count;
                    let vec_x = this.DIG_RADIUS * Math.cos(r);
                    let vec_y = this.DIG_RADIUS * Math.sin(r);
                    let x, y;
                    if (Cocos_Api_MG.dot(xiangcha, { x: vec_x, y: vec_y }) > 0) {
                        x = pos.x + vec_x;
                        y = pos.y + vec_y;
                    } else {
                        x = startPos.x + vec_x;
                        y = startPos.y + vec_y;
                    }
                    var pos_reg = this._optimizePoint([x, y]);
                    regions.push({ x: pos_reg[0], y: pos_reg[1] });

                }

                this.LastMousePos = { x: pos.x, y: pos.y };
            } else {
                return
            }
            if (regions.length != 0) {//如果顶点数>0 去绘制
                this.CreatFirst = false;//不是首次绘制 
                this.pushCommand('polyDifference', [regions]);//添加进 处理队列
            }
        }
        this.SetPenPos();
    }
    /**设置画笔位置 */
    SetPenPos() {

        this.GameUI.HuaBiY.pos(this.GameUI.SceneBox.mouseX, this.GameUI.SceneBox.mouseY);
    }
    /**
    * 重置 初始化
    */
    reset() {
        this.CreatFirst = true;//第一次创建不用多边形 用圆球碰撞体
        //对象池 创建一个sprite对象 用于绘制线条 和添加物理
        this.DrawSprite = Laya.Pool.getItemByClass("DrawSp", Laya.Sprite);
        this.DrawSprite.key = "DrawSp";
        this._commands = [];//事件队列列表 也就说每次抬手就要清除队列 不再继续添加后面的绘制
        this._regions = [];//当前对象的所有顶点列表
        if (this.DrawSprite.getComponent(Laya.RigidBody)) {//销毁所有物理 方便再次添加新的 
            var collders = this.DrawSprite.getComponents(Laya.ColliderBase);
            var RigidBody = this.DrawSprite.getComponent(Laya.RigidBody);
            RigidBody.destroy();
            for (var a = 0; a < collders.length; a++) {
                collders[a].destroy();
            }
        }
		
        this.DrawSprite.x = 0;
        this.DrawSprite.y = 0;
        this.DrawSprite.rotation = 0;
        
        this.scene.addChild(this.DrawSprite);


        //----------------------------点一下 先绘制一个原球
        var regions = [];
        var pos = { x: this.scene.mouseX, y: this.scene.mouseY };
        for (let index = 0; index < this.DIG_FRAGMENT; index++) {
            var r = 2 * Math.PI * index / this.DIG_FRAGMENT;
            var x = pos.x + this.DIG_RADIUS * Math.cos(r);
            var y = pos.y + this.DIG_RADIUS * Math.sin(r);
            var pos_reg = this._optimizePoint([x, y]);
            regions.push({ x: pos_reg[0], y: pos_reg[1] });

        }
        this.LastMousePos = { x: pos.x, y: pos.y };
        this.polyDifference(regions);
        //-----------



    }
    //方案2 clipper.js
    polyDifference(regions = []) {
        //-----------clipper.js  此区域的代码请参考此库文档 https://www.cnblogs.com/zhigu/p/11928492.html
        // // 计算新的多边形
        var cpr = new ClipperLib.Clipper(ClipperLib.Clipper.ioStrictlySimple); //ClipperLib.Clipper.ioStrictlySimple  | ClipperLib.Clipper.ioPreserveCollinear
        var subj_paths = this._regions;
        var clip_paths = [this._convertVecArrayToClipperPath(regions)]
        cpr.AddPaths(subj_paths, ClipperLib.PolyType.ptSubject, true);//添加主多边形顶点集合
        cpr.AddPaths(clip_paths, ClipperLib.PolyType.ptClip, true);//添加 需要计算的多边形顶点集合 
        var subject_fillType = 0;//类型 具体看文档说明 0 1 2 3
        var clip_fillType = 0;//类型 具体看文档说明 0 1 2 3
        var solution_polytree = new ClipperLib.PolyTree();
        var clipTypes = [ClipperLib.ClipType.ctUnion, ClipperLib.ClipType.ctDifference, ClipperLib.ClipType.ctXor, ClipperLib.ClipType.ctIntersection];//并集  差集 去共合并 交集
        cpr.Execute(clipTypes[0], solution_polytree, subject_fillType, clip_fillType);//这步就算出来 合并后的多边形
        var solution_expolygons = ClipperLib.JS.PolyTreeToExPolygons(solution_polytree);//转换顶点格式
        this._regions = ClipperLib.Clipper.PolyTreeToPaths(solution_polytree);//储存顶点
        this.DrawPoly(solution_expolygons);//绘制多边形
    }
    DrawPoly(solution_expolygons) {//绘制多边形
        this.DrawSprite.graphics.clear();//先清除绘制
        var triangles = this.SetTriangle(solution_expolygons[0]);//先将多边形转换为三角形处理 否则圈圈效果会出现封闭现象 绘制问题不是库问题
        this.DrawSprite.ColliderArray = [];//储存所有的物理位置节点
        for (var tri of triangles) {
            // 逐一处理三角形

            var pos = tri.getPoints().map((v, i) => {
                return [v.x, v.y];
            });
            var pp = pos.map((v, i) => {
                var v2 = v[0] + "," + v[1];
                return v2;
            });
            var poins = "";
            for (var a = 0; a < pp.length; a++) {
                if (a != 0) {
                    poins += ",";
                }
                poins += pp[a];
            }
            this.DrawSprite.ColliderArray.push(poins);
            var popo = [];
            for (var a = 0; a < pos.length; a++) {
                popo.push(pos[a][0]);
                popo.push(pos[a][1]);
            }
            this.DrawSprite.graphics.drawPoly(0, 0, popo, this.DrawColor);
        }
        this.DrawSprite.CirclePos = { x: this.scene.mouseX - this.DIG_RADIUS, y: this.scene.mouseY - this.DIG_RADIUS };//储存圆点位置 方便小球物理生成位置


    }

    DrawPhy() {//绘制物理 并添加到场景
        var rig = this.DrawSprite.addComponent(Laya.RigidBody);//添加物理
        if (this.CreatFirst) {//判断是创建球形物理还是多边形物理
            var collder = this.DrawSprite.addComponent(Laya.CircleCollider);
            collder.radius = this.DIG_RADIUS;
            collder.x = this.DrawSprite.CirclePos.x;
            collder.y = this.DrawSprite.CirclePos.y;
        } else {
            for (var tri of this.DrawSprite.ColliderArray) {
                // 逐一处理三角形
                var collder = this.DrawSprite.addComponent(Laya.PolygonCollider);
                collder.points = tri;
            }
        }
        if (!this.DrawSprite.getComponent(Phy)) {
            this.DrawSprite.addComponent(Phy);//添加超出屏回收处理
        }


    }
    /**
     * 将多边形处理成三角形集合
     * @param {*} expolygon 
     */
    SetTriangle(expolygon) {
        //---这里需要去 了解poly2tri.js 将多边形转换为三角形
        let _physicsPolygonColliders_count = 0;
        var countor = this._convertClipperPathToPoly2triPoint(expolygon.outer);
        if (countor.length < 2) return [];
        var swctx = new poly2tri.SweepContext(countor, { cloneArrays: true });
        // var exclude = countor;
        var holes = expolygon.holes.map(h => { return this._convertClipperPathToPoly2triPoint(h, countor) });
        try {
            // 防止 addhole 失败 使用try
            swctx.addHoles(holes);
            swctx.triangulate();
            var triangles = swctx.getTriangles();
            return triangles;
        } catch (e) {
            console.error('polyDifference poly2tri error', _physicsPolygonColliders_count, expolygon);
            console.error(e);

        }
    }
    /**添加事件 */
    pushCommand(name = "", params = []) {
        this._commands.push({ name, params });
    }
    lateUpdate(dt) {//缓针执行
        if (this._commands.length) {
            // 每帧执行命令队列
            for (let index = 0; index < 2; index++) {
                var cmd = this._commands.shift();
                if (cmd)
                    this[cmd.name](...cmd.params);//...扩展运算符 将数组转换为逗号隔开的参数
                else
                    break;
            }
        }
    }
    //类型转换 1
    _convertVecArrayToClipperPath(poly = []) {
        var s = poly.map((p) => {
            return { X: p.x, Y: p.y }
        });
        return s
    }
    //类型转换  2
    _convertClipperPathToVecArray(poly = []) {
        return poly.map((p) => { return { X: p.x, Y: p.y } });
    }
    //类型转换 3
    _convertClipperPathToPoly2triPoint(poly = [], exclude = []) {
        // return poly.map((p) => { return new poly2tri.Point(p.X, p.Y) });
        var newPos = [];
        poly.forEach((p, i) => {
            var p_now = new poly2tri.Point(p.X, p.Y)
            var isIn = exclude.some((e_p) => {
                if (e_p.equals(p_now)) {
                    return true;
                }
            })
            if (!isIn) {
                newPos.push(p_now);
                exclude.push(p_now);
            }
        })
        if (newPos.length > 2)
            return newPos;
        else
            return [];

    }
    /**Point转换为整数 去掉小数计算 */
    _optimizePoint(point) {
        var DIG_OPTIMIZE_SIZE = 1;
        return [Math.floor(point[0] * DIG_OPTIMIZE_SIZE) / DIG_OPTIMIZE_SIZE, Math.floor(point[1] * DIG_OPTIMIZE_SIZE) / DIG_OPTIMIZE_SIZE];
    }
    /**
     * 回收物理对象
     * @param {Laya.Sprite} Node 对象
     */
    static Remove(Node = new Laya.Sprite()) {

        Laya.Pool.recover(Node.key, Node);
        Node.removeSelf();
    }
    /**
    * 获取min~max的整数 例如-50~50
    * @param {*} min 最小数整数
    * @param {*} max 最大数正整数
    */
    GetRandNub2(min, max) {
        var biaoxu = 0;
        if (min < 0) {
            biaoxu = min * -1;
            max += biaoxu;
            min = 0;
        }
        return Math.floor(Math.random() * (max - min + 1) + min) - biaoxu; //0-10
    }


}
/**判断是否回收 */
class Phy extends Laya.Script {

    constructor() {
        super();
    }
    // onLateUpdate() {
    //     if (this.owner.y > Laya.stage.height + 200) {
    //         GameRun.Remove(this.owner);//回收
    //     }
    // }
    onTriggerEnter(other) {
        if (other.owner.name == "Recover") {//游戏胜利
            GameRun.Remove(this.owner);//回收
        }
    }
}
/**判断是否胜利 */
class BallPhy extends Laya.Script {

    constructor(that) {
        super();
        this.that = that;
    }
    onTriggerEnter(other) {
        if (other.owner.name == "BallB") {//游戏胜利
            this.that.moveCeng.off(Laya.Event.MOUSE_DOWN, this.that, this.that.GameDown);
            this.that.GameUI.GameWin();
        }
    }
}
