import { GameFIG_VV } from "./GameFIG_VV";

export default class Debug extends Laya.Scene {

    constructor() {
        super();
        Laya.Scene.closeAll = () => {//重写一下防止吧当前场景关闭
            var root = Laya.Scene.root;
            for (var i = 0, n = root.numChildren; i < n; i++) {
                var scene = root.getChildAt(0);
                if (scene._Lock_) { continue }
                if (scene instanceof Scene)
                    scene.close();
                else
                    scene.removeSelf();
            }
        }
    }

    onEnable() {
        this.GameFIG = GameFIG_VV.Get();
        this.GameFIG.DebugThis = this;
        var this_ = this;
        console.oldLog = console.log;
        console.log = function (str, ...optionalParams) {
            console.oldLog(str, ...optionalParams);
            this_.log(str);
        }
        console.olderr = console.error;
        console.error = function (str, ...optionalParams) {
            console.olderr(str, ...optionalParams);
            this_.log("!!!错误:" + str + optionalParams.toString());
        }
        console.oldwarn = console.warn;
        console.warn = function (str, ...optionalParams) {
            console.oldwarn(str, ...optionalParams);
            this_.log("!!!警告:" + str + optionalParams.toString());
        }
        console.log("aaa", "bbb");
        console.error("aaa", "bbb");
        console.warn("aaa", "bbb");
        this.Console_but.on(Laya.Event.MOUSE_DOWN, this, this.onStartDrag)
        this.Detext.height = Laya.stage.height;
        this.back.graphics.drawRect(0, 0, Laya.stage.width, Laya.stage.height, "#b9ffd7")
        this.height = Laya.stage.height;
        this._Lock_ = true;
        this.zOrder = 9999;//最高
        this.Console_but.on(Laya.Event.CLICK, this, this.OpenText);
    }
    OpenText() {
        this.back.visible = !this.back.visible;
        this.Detext.visible = !this.Detext.visible;
        this.Detext.mouseEnabled = this.Detext.visible;

    }
    onStartDrag(e) {
        var dragRegion = new Laya.Rectangle(0, 0, Laya.stage.width - this.Console_but.width, Laya.stage.height - this.Console_but.height);

        //鼠标按下开始拖拽(设置了拖动区域和超界弹回的滑动效果)
        this.Console_but.startDrag(dragRegion, true, 10);
    }
    /**
     * 打印
     * @param {*} msg 内容
     * @param {*} TFtime 是否显示时间 yyyy-mm-dd hh:mm:ss
     */
    log(msg, TFtime = false) {
        var time1 = "";
        if (TFtime) {
            time1 = new Date().Format("yyyy-MM-dd hh:mm:ss") + "\n";
        }

        this.Detext.text += time1 + msg + "\n";
        this.Detext.scrollY += Laya.stage.height;
    }
    onDisable() {
    }
}