export default class GameUI extends GameAll {//主场景逻辑管理脚本 UI逻辑 游戏主逻辑
    constructor() {
        super();

    }
    onEnable() {//场景启动
    
        this.SetScene();//设置场景图片
        this.UIMMP();//自适应UI等
        this.Addbut();//添加按钮点击事件
    }
    /** 设置场景图片*/
    SetScene() {
        for (var a = 0; a < 6; a++) {//循环设置每个节点
            if (a < this.windowUser.sceneArrPIC.length) {
                this["S" + a].getChildByName("back").texture = this.windowUser.sceneArrPIC[a];
                this["S" + a].getChildByName("GK").text = this.windowUser.NowYE * 6 + a + 1;
                this["S" + a].visible = true;
                var GKid = this.windowUser.NowYE * 6 + a;
                if (this.GameFIG_Config.player_Config.NowJS < GKid) {//判断是否解锁
                    this["S" + a].getChildByName("mk").visible = true;
                    this["S" + a].getChildByName("win").visible = false;
                    this["S" + a].getChildByName("fail").visible = false;
                    if (this.GameFIG_Config.player_Config.NowJS + 1 == GKid) {//可以提前解锁
                        this["S" + a].getChildByName("Next").visible = true;
                        this["S" + a].getChildByName("Lock").visible = false;
                        this.GameFIG.butTween(this["S" + a], Laya.Handler.create(this, this.LookOpen, [GKid], false), 0, true, "#0e3456");//提示
                    } else {
                        this["S" + a].getChildByName("Next").visible = false;
                        this["S" + a].getChildByName("Lock").visible = true;
                        this.GameFIG.butTween(this["S" + a], Laya.Handler.create(this, ()=>{
                            this.GameFIG.TiShiKuang("优先解锁前面关卡");
                        }, [GKid], false), 0, true, "#0e3456");//开始
                    }
                } else {//已解锁
                    this["S" + a].getChildByName("mk").visible = false;
                    this["S" + a].getChildByName("Next").visible = false;
                    this["S" + a].getChildByName("Lock").visible = false;
                    if (this.GameFIG_Config.player_Config.WinGk[GKid] == true) {
                        this["S" + a].getChildByName("win").visible = true;
                        this["S" + a].getChildByName("fail").visible = false;
                    } else {//未完成的关卡
                        this["S" + a].getChildByName("win").visible = false;
                        if (GKid == this.GameFIG_Config.player_Config.NowGK) {
                            this["S" + a].getChildByName("fail").visible = true;
                        } else {
                            this["S" + a].getChildByName("fail").visible = false;
                        }
                    }
                    this.GameFIG.butTween(this["S" + a], Laya.Handler.create(this, this.GameBegin, [GKid], false), 0, true, "#0e3456");//开始

                }

            } else {
                this["S" + a].visible = false;
            }

        }
        this.SetNextLast();//设置 上下页 按钮
    }
    UIMMP() {
        var ViewArr = [
            this.View_ZJM,
            this.View_Gane,
            this.View_HB
        ];
        this.GameFIG.InitViewToView(ViewArr);//方便页面跳转
        for (var a = 0; a < this.numChildren; a++) {//将所有box的宽高设置成手机的宽高
            var node = this.getChildAt(a);
            node.width = Laya.stage.width;
            node.height = Laya.stage.height;
        }
        this.width = Laya.stage.width;
        this.height = Laya.stage.height;

    }
    Addbut() {

        this.GameFIG.butTween(this.addDesk, Laya.Handler.create(this.GameFIG, this.GameFIG.AddDesktop, [], false), 0, true, "#211f1f");//添加桌面按钮
        this.GameFIG.butTween(this.LastBut, Laya.Handler.create(this, this.SceneNextLast, [false], false), 0, true, "#0e3456");//上一页
        this.GameFIG.butTween(this.NextBut, Laya.Handler.create(this, this.SceneNextLast, [true], false), 0, true, "#0e3456");//下一页

        this.GameFIG.butTween(this.GameBack, Laya.Handler.create(this, this.GameReture, [true], false), 0, true, "#0e3456");//返回
        this.GameFIG.butTween(this.GameRecover, Laya.Handler.create(this, this.GameRest, [true], false), 0, true, "#0e3456");//重新
        this.GameFIG.butTween(this.GameTS, Laya.Handler.create(this, this.GameTishi, [true], false), 0, true, "#0e3456");//游戏提示
        this.GameFIG.butTween(this.HuaBi, Laya.Handler.create(this, this.OpenHuaB, [false], false), 0, true, "#0e3456");//主界面画笔
        this.GameFIG.butTween(this.GameHuaBi, Laya.Handler.create(this, this.OpenHuaB, [true], false), 0, true, "#0e3456");//游戏画笔
        this.GameFIG.butTween(this.HB_close, Laya.Handler.create(this, this.CloseHuaB, [true], false), 0, true, "#0e3456");//游戏画笔

    }
    SceneNextLast(ttff) {//切换
        this.OpenCloseClick(false);
        if (ttff) {//下一页
            this.windowUser.LoadMapPic(this.windowUser.NowYE + 1, Laya.Handler.create(this, () => {
                this.OpenCloseClick(true);
                this.SetScene();
            }));
        } else {//上一页
            this.windowUser.LoadMapPic(this.windowUser.NowYE - 1, Laya.Handler.create(this, () => {
                this.OpenCloseClick(true);
                this.SetScene();
            }));
        }

    }
    /**打开关闭场景点击事件 */
    OpenCloseClick(ttff) {
        this.LastBut.mouseEnabled = ttff;
        this.NextBut.mouseEnabled = ttff;
        for (var a = 0; a < 6; a++) {
            this["S" + a].mouseEnabled = ttff;
        }
    }
    SetNextLast() {//设置上下页按钮
        var AllYe = Math.ceil(this.windowUser.MapLeng / 6);//总页数
        if (this.windowUser.NowYE == 0) {
            this.LastBut.visible = false;
        } else {
            this.LastBut.visible = true;
        }
        if (this.windowUser.NowYE == AllYe - 1) {
            this.NextBut.visible = false;
        } else {
            this.NextBut.visible = true;
        }
    }
    /**
     * 观影解锁
     * @param {*} GKID 
     */
    LookOpen(GKID = 0) {
        this.GameFIG.GG_all(true, Laya.Handler.create(this, () => {
            this.GameFIG.player_Config.NowJS += 3;
            this.GameFIG.UpdatePlayerMsg();
            this.SetScene();
        }))
    }
    /**
     * 游戏开始
     * @param {Number} GKID 关卡ID
     */
    GameBegin(GKID = 0, TGG = false) {//游戏开始
        this.TishiGG = TGG;//广告可以看一局提示
        this.GameRunID = GKID;//储存当前玩关卡ID
        Laya.physicsTimer.pause();//暂停物理模拟
        this.GameFIG.ViewToView(0, 1, true, false);//切换到游戏界面

        Laya.Scene.load("Map/" + GKID + ".scene", Laya.Handler.create(this, (scene) => {//载入对应关卡场景
            scene.pivotY = 719;//设置锚点为底部方便把场景底部居中
            scene.x = this.SceneBox.width / 2 - scene.width / 2;
            scene.y = Laya.stage.height - 20;
            this.SceneBox.addChild(scene);
            var script = new GameRun(scene, this)//给场景添加游戏脚本
            scene.addComponentIntance(script);
            this.GameScene = scene;
            this.CreatHuaBI();
            // this.GameScene.addChildAt(this.MoveCeng, 0);
        }))
    }
    /**游戏返回主界面 */
    GameReture() {
        this.GameScene.destroy();
        this.GameFIG.ViewToView(1, 0, true, false);
    }
    /**游戏胜利 */
    GameWin() {
        this.GameFIG.PlaySound(1);
        //-----储存玩家数据 判断是否解锁新关卡 目前是玩完所有未解锁后 自动解锁3关
        this.GameFIG.player_Config.WinGk[this.GameRunID] = true;//储存玩家已胜利关卡
        var keys = Object.keys(this.GameFIG.player_Config.WinGk);
        if (keys.length >= this.GameFIG.player_Config.NowJS + 1) {//判断是否完成已解锁数量的关卡
            this.GameFIG.player_Config.NowJS += 3;
        }
        this.GameFIG.player_Config.NowGK = this.GameRunID + 1;//储存当前正在玩的关卡
        this.GameFIG.UpdatePlayerMsg();
        this.SetScene();
        console.log("游戏胜利")
        Laya.physicsTimer.pause();//暂停游戏物理模拟 防止球再次碰撞触发 胜利
        this.OpenView(this.viewAll.Win, {//打开胜利场景
            GameUI_: this
        }, false, false, false);

    }
    /**下一关游戏 */
    GameNext() {
        this.GameScene.destroy();
        this.GameRunID++;
        if (this.GameRunID > this.GameFIG.player_Config.NowJS || this.GameRunID >= this.windowUser.MapLeng) {//判断下一关是否未解锁 是否还有下一关
            this.GameReture();
        } else {
            this.GameBegin(this.GameRunID)
        }

    }
    /**游戏重新开始 */
    GameRest() {
        this.GameScene.destroy();
        this.GameBegin(this.GameRunID, this.TishiGG)
    }
    /**打开游戏提示 */
    GameTishi() {
        if (!this.TishiGG) {//判断当前关卡是否已经观看视频  看了当前关卡下次就不需要看了 除非退出主界面重进
            this.GameFIG.GG_all(true, Laya.Handler.create(this.GameScene, () => {
                this.GameScene.ShowTishi();
                this.TishiGG = true;//广告可以看一局提示
            }))
        } else {
            this.GameScene.ShowTishi();
        }
    }
    /**
     * 打开画笔界面
     * @param {Boolean} ttff 关闭是否更新当前场景画笔
     */
    OpenHuaB(ttff = false) {
        this.SetPen();
        this.View_HB.visible = true;
        this.CloseHB_ = ttff;

    }
    /**关闭画笔界面 */
    CloseHuaB() {

        this.View_HB.visible = false;
        if (this.CloseHB_) {//更新游戏画笔
            this.CreatHuaBI();
            this.GameScene.ChangeHuaB();
        }
    }
    CreatHuaBI() {//创建画笔
        this.HuaBiY.texture = this.windowUser.HuaBiFIG[this.GameFIG.player_Config.Pen.nowPF].URL;
    }
    /**设置画笔界面 */
    SetPen() {
        for (var a = 0; a < 5; a++) {
            var node = this["Pen" + a];
            var suo = node.getChildAt(3);
            var But = node.getChildAt(2);
            var Lab = But.getChildAt(0);
            if (this.GameFIG.player_Config.Pen.have[a]) {//已经拥有
                suo.visible = false;
                if (this.GameFIG.player_Config.Pen.nowPF == a) {//当前正在使用
                    Lab.text = "正在使用";
                } else {
                    Lab.text = "使用";
                    this.GameFIG.butTween(But, Laya.Handler.create(this, this.ChoosePen, [a], false), 0, true, "#0e3456");//选择
                }
            } else {//未解锁
                suo.visible = true;
                Lab.text = "视频解锁";
                this.GameFIG.butTween(But, Laya.Handler.create(this, this.GetPen, [a], false), 0, true, "#0e3456");//选择
            }

        }
    }
    /**
     * 选择画笔
     * @param {*} ID 画笔ID 对应windowuer.HuaBiFIG.ID
     */
    ChoosePen(ID) {
        this.GameFIG.player_Config.Pen.nowPF = ID;
        this.GameFIG.UpdatePlayerMsg();
        this.SetPen();
    }
    /**获取画笔 */
    GetPen(ID) {
        this.GameFIG.GG_all(true, Laya.Handler.create(this, () => {
            this.GameFIG.player_Config.Pen.have[ID] = true;
            this.GameFIG.UpdatePlayerMsg();
            this.SetPen();
        }))
    }
}

